protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
    // Preserve the old name so existing documents remain readable.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // EF Core 9 removed the discriminator prefix from JSON id values.
    // Preserve "Blog|1" format so existing documents are still found by key.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // HasIndex was removed — throws at startup in EF Core 9.
    // Cosmos DB indexing is managed via the container's indexing policy, not EF.
}

